const inv = $input.first().json.data.object;

function amount(value) {
    return (Number(value || 0) / 100).toFixed(2);
}

function formatDate(timestamp) {
    return timestamp ? new Date(timestamp * 1000).toISOString().slice(0, 10) : null;
}

const symbols = {
    usd: '$',
    eur: '€',
    gbp: '£',
    pln: 'zł',
    cad: '$',
    aud: '$',
};

const currency = inv.currency || 'usd';
const currencySymbol = symbols[currency] || currency.toUpperCase();

const lineItems = inv.lines.data.map((line) => {
    const quantity = Number(line.quantity_decimal || line.quantity || 1);
    const total = Number(line.amount || 0) / 100;

    const unitAmount = line.pricing?.unit_amount_decimal != null
        ? Number(line.pricing.unit_amount_decimal) / 100
        : line.price?.unit_amount != null
            ? Number(line.price.unit_amount) / 100
            : total / quantity;

    return {
        description: line.description || 'Item',
        quantity: String(quantity),
        unit_price: unitAmount.toFixed(2),
        total_amount: total.toFixed(2),
    };
});

const taxAmount = Array.isArray(inv.total_taxes)
    ? inv.total_taxes.reduce((sum, tax) => sum + Number(tax.amount || 0), 0) / 100
    : Array.isArray(inv.total_tax_amounts)
        ? inv.total_tax_amounts.reduce((sum, tax) => sum + Number(tax.amount || 0), 0) / 100
        : Number(inv.tax || 0) / 100;

const templateData = {
    invoice_number: inv.number || `INV-${inv.id}`,
    issue_date: formatDate(inv.created),
    due_date: formatDate(inv.due_date),

    client_name: inv.customer_name || 'Customer',
    client_email: inv.customer_email,
    client_phone: inv.customer_phone,
    client_address_street: inv.customer_address?.line1,
    client_address_line2: inv.customer_address?.line2,
    client_city: inv.customer_address?.city,
    client_state: inv.customer_address?.state,
    client_postal_code: inv.customer_address?.postal_code,
    client_country: inv.customer_address?.country,
    client_tax_id: inv.customer_tax_ids?.[0]?.value,

    currency_symbol: currencySymbol,
    line_items: lineItems,
    subtotal_amount: amount(inv.subtotal),
    tax_amount: taxAmount > 0 ? taxAmount.toFixed(2) : null,
    total_amount: amount(inv.total),
    notes: 'Paid via Stripe.',
};

if (!templateData.client_email) {
    throw new Error('Customer email is required to send the invoice.');
}

return [{
    json: {
        templateData,
        customerEmail: templateData.client_email,
        customerName: templateData.client_name,
        invoiceNumber: templateData.invoice_number,
        totalAmount: `${templateData.currency_symbol}${templateData.total_amount}`,
        filename: `invoice-${templateData.invoice_number}.pdf`,
    },
}];
